command:
// Modern performance-enhancing — gym-energy red outline with a heartbeat pulse.
if (!game.modules.get("tokenmagic")?.active) return;
if (!token) return;
const filterId = "fishut-tmfx-modern-performance-enhancing";
if (mode === "remove") { await TokenMagic.deleteFiltersOnToken(token, filterId); return; }
await TokenMagic.addUpdateFiltersOnToken(token, [{
  filterType: "outline",
  filterId,
  color: 0xff1a1a,
  thickness: 2,
  quality: 5,
  padding: 4,
  animated: { thickness: { active: true, loopDuration: 1200, animType: "syncCosOscillation", val1: 1, val2: 3 } }
}]);
